// FIX BLOQUEO D — Validar chat_id antes de llamar al DAL
// Previene error: invalid input syntax for type bigint: "null"
const raw = $input.first()?.json || {};
const chatId = Number(raw.chat_id);

if (!chatId || isNaN(chatId) || chatId <= 0) {
  // Retornar respuesta controlada sin llamar al DAL
  return [{
    json: {
      _skip_dal: true,
      success: true,
      registered: false,
      data: null,
      message: 'El usuario es nuevo (no registrado). No tiene perfil ni citas activas en la base de datos.'
    }
  }];
}

return [{ json: { ...raw, chat_id: chatId, _skip_dal: false } }];

// Respuesta directa para chat_id inválido (usuario nuevo asumido)
const validated = $('Validate chat_id').item.json;
return [{
  json: {
    success: true,
    message: validated.message || 'El usuario es nuevo (no registrado). No tiene perfil ni citas activas en la base de datos.',
    error_code: null,
    error_message: null,
    data: { registered: false, active_bookings: [] },
    _meta: { source: 'DB_Get_User_Profile', timestamp: new Date().toISOString(), version: '3.0.2' }
  }
}];

// Format user profile con message legible para el LLM
const result = $input.first().json;
const isRegistered = result.registered === true;
const isSuccess    = result.success === true;

return [{
  json: {
    success: isSuccess,
    message: isSuccess && isRegistered
      ? `Perfil encontrado. Nombre: ${result.data?.full_name || result.full_name}. Email: ${result.data?.email || result.email}.`
      : (isSuccess ? 'El usuario es nuevo (no registrado). No tiene perfil ni citas activas en la base de datos.' : 'Error técnico al obtener el perfil.'),
    error_code:    isSuccess ? null : 'DAL_ERROR',
    error_message: isSuccess ? null : 'Failed to fetch user profile',
    data: isSuccess ? {
      registered:   isRegistered,
      user_id:      result.data?.user_id   || null,
      full_name:    result.data?.full_name  || result.full_name  || null,
      email:        result.data?.email      || result.email      || null,
      phone:        result.data?.phone      || null,
      active_bookings: result.data?.active_bookings || []
    } : null,
    _meta: { source: 'DB_Get_User_Profile', timestamp: new Date().toISOString(), version: '3.0.2' }
  }
}];

// 📤 STANDARD CONTRACT OUTPUT — Tool-compatible (v3.0.0)
const result = $input.first()?.json || {};
const isSuccess = result.success !== false;

let message = result.message || result.data?.message || null;
if (!message) {
  message = isSuccess
    ? 'Operación completada con éxito.'
    : (result.error_message || result.error_code || 'Error desconocido.');
}

return [{
  json: {
    success: isSuccess,
    message,
    error_code:    isSuccess ? null : (result.error_code    || 'UNKNOWN_ERROR'),
    error_message: isSuccess ? null : (result.error_message || message),
    data:          result.data || null,
    _meta: {
      source:    'DB_GET_USER_PROFILE',
      timestamp: new Date().toISOString(),
      version:   '3.0.2'
    }
  }
}];
